const input = $input.first().json;
const payload = input.payload ?? input;
const text = String(payload.message ?? '').toLowerCase();
const highRisk = ['enviar', 'apagar', 'excluir', 'ativar workflow', 'desativar workflow', 'producao'].some((word) => text.includes(word));
if (highRisk) {
  return [{ json: { event_id: payload.event_id, status: 'pending_approval', action: 'no_reply', recipient_phone: payload.sender_phone, message: 'Acao sensivel preparada e aguardando aprovacao.', risk: 'high', approval_required: true, metadata: { audience: 'internal' } } }];
}
return [{ json: { event_id: payload.event_id, status: 'success', action: 'send_reply', recipient_phone: payload.sender_phone, message: 'Recebi o comando interno. Vou operar em modo seguro e registrar a execucao.', risk: 'low', approval_required: false, metadata: { audience: 'internal', tool_policy: 'operator_safe' } } }];
